import React from 'react';
import { ActivityIndicator, type ColorValue, type ViewStyle } from 'react-native';
import type { StyleProp } from 'react-native';
import type {ILoaderProps} from "@lmb-it/kitsconcerto-types";

type NativeLoaderProps = ILoaderProps<
    ColorValue,
    StyleProp<ViewStyle>,
    Record<string, unknown>
>;

const Loader = ({ color, size = 'large', animating = true, style }: NativeLoaderProps) => (
    <ActivityIndicator color={color} size={size === 'small' ? 'small' : 'large'} animating={animating} style={style} />
);
export default Loader;
